func generatedReadCaseScalarString(tc testgen.GeneratedReadCase) (string, string, error) {
	switch tc.OutputType {
	case "OP_BIN32":
		value, status, err := nativeReadtestGeneratedBinary32(tc.Function, tc.Rounding, tc.Operands)
		if err != nil {
			return "", "", err
		}
		return fmt.Sprintf("[%08x]", value), status, nil
	case "OP_BIN64":
		value, status, err := nativeReadtestGeneratedBinary64(tc.Function, tc.Rounding, tc.Operands)
		if err != nil {
			return "", "", err
		}
		return fmt.Sprintf("[%016x]", value), status, nil
	case "OP_BIN128":
		value, status, err := nativeReadtestGeneratedBinary128(tc.Function, tc.Rounding, tc.Operands)
		if err != nil {
			return "", "", err
		}
		return formatGeneratedReadtestBits128(value), status, nil
	case "OP_BID_UINT8", "OP_BID_UINT16", "OP_BID_UINT32", "OP_BID_UINT64":
		value, status, err := nativeReadtestGeneratedUnsigned(tc.Function, tc.Rounding, tc.Operands)
		if err != nil {
			return "", "", err
		}
		return strconv.FormatUint(value, 10), status, nil
	case "OP_INT8", "OP_INT16", "OP_INT32", "OP_INT64", "OP_LINT":
		value, status, err := nativeReadtestGeneratedSigned(tc.Function, tc.Rounding, tc.Operands)
		if err != nil {
			return "", "", err
		}
		return strconv.FormatInt(value, 10), status, nil
	default:
		return "", "", fmt.Errorf("unsupported scalar output %q", tc.OutputType)
	}
}

func isGeneratedReadScalarOutput(output string) bool {
	switch output {
	case "OP_BIN32", "OP_BIN64", "OP_BIN128",
		"OP_BID_UINT8", "OP_BID_UINT16", "OP_BID_UINT32", "OP_BID_UINT64",
		"OP_INT8", "OP_INT16", "OP_INT32", "OP_INT64", "OP_LINT":
		return true
	default:
		return false
	}
}

func parseGeneratedReadtestUintBits(input string, bits int) (uint64, error) {
	trimmed := strings.TrimSuffix(strings.TrimPrefix(strings.TrimSpace(input), "["), "]")
	trimmed = strings.ReplaceAll(trimmed, ",", "")
	return strconv.ParseUint(trimmed, 16, bits)
}

func normalizeGeneratedReadtestBits(input string) string {
	trimmed := strings.ToLower(strings.TrimSpace(input))
	if strings.HasPrefix(trimmed, "[") && strings.HasSuffix(trimmed, "]") {
		trimmed = strings.TrimSuffix(strings.TrimPrefix(trimmed, "["), "]")
	}
	trimmed = strings.ReplaceAll(trimmed, ",", "")
	if len(trimmed) > 16 && len(trimmed) <= 32 {
		if raw, err := parseGeneratedReadtestBits128(input); err == nil {
			return formatGeneratedReadtestBits128(raw)
		}
	}
	trimmed = strings.TrimLeft(trimmed, "0")
	if trimmed == "" {
		trimmed = "0"
	}
	return "[" + trimmed + "]"
}

func compareGeneratedReadScalarOutput(outputType, expected, got string) bool {
	expected = strings.TrimSpace(strings.TrimPrefix(expected, "+"))
	got = strings.TrimSpace(strings.TrimPrefix(got, "+"))

	switch outputType {
	case "OP_BIN32", "OP_BIN64", "OP_BIN128":
		return normalizeGeneratedReadtestBits(expected) == normalizeGeneratedReadtestBits(got)
	case "OP_BID_UINT8":
		return normalizeGeneratedReadUnsignedScalar(expected, 8) == normalizeGeneratedReadUnsignedScalar(got, 8)
	case "OP_BID_UINT16":
		return normalizeGeneratedReadUnsignedScalar(expected, 16) == normalizeGeneratedReadUnsignedScalar(got, 16)
	case "OP_BID_UINT32":
		return normalizeGeneratedReadUnsignedScalar(expected, 32) == normalizeGeneratedReadUnsignedScalar(got, 32)
	case "OP_BID_UINT64":
		return normalizeGeneratedReadUnsignedScalar(expected, 64) == normalizeGeneratedReadUnsignedScalar(got, 64)
	default:
		return expected == got
	}
}

func normalizeGeneratedReadUnsignedScalar(input string, bits int) string {
	if value, err := strconv.ParseUint(input, 10, bits); err == nil {
		return strconv.FormatUint(value, 10)
	}
	signed, err := strconv.ParseInt(input, 10, bits)
	if err != nil {
		return input
	}
	switch bits {
	case 8:
		return strconv.FormatUint(uint64(uint8(signed)), 10)
	case 16:
		return strconv.FormatUint(uint64(uint16(signed)), 10)
	case 32:
		return strconv.FormatUint(uint64(uint32(signed)), 10)
	case 64:
		return strconv.FormatUint(uint64(signed), 10)
	default:
		return input
	}
}

func normalizeGeneratedReadtestStatus(input string) string {
	trimmed := strings.ToUpper(strings.TrimSpace(input))
	trimmed = strings.TrimPrefix(trimmed, "0X")
	if trimmed == "" {
		return "00"
	}
	if len(trimmed)%2 != 0 {
		trimmed = "0" + trimmed
	}
	return trimmed
}
